const msg = $('Telegram Trigger').first().json.message;
const sessionArr = $('Get Session').first().json;
const session = Array.isArray(sessionArr) ? sessionArr[0] : sessionArr;
const chatId = String(msg.chat.id);
const text = msg.text || '';
const isVoice = !!msg.voice;
const hasSession = session && session.chat_id;
const step = hasSession ? (session.step || 1) : 0;

let action = 'unknown';
let payload = { chatId };

if (text.startsWith('/diary')) {
  action = 'start_diary';
  payload = { chatId };
} else if (text.startsWith('/goals')) {
  action = 'goals';
  payload = { chatId, command: text.replace('/goals', '').trim() || 'show' };
} else if (isVoice && hasSession && step >= 1 && step <= 5) {
  action = 'voice_answer';
  payload = { chatId, fileId: msg.voice.file_id, step, session };
} else if (!isVoice && text && hasSession && step === 6) {
  action = 'metrics';
  payload = { chatId, metricsText: text, session };
} else if (isVoice && !hasSession) {
  // Voice without session -> auto start
  action = 'start_diary_then_ask';
  payload = { chatId };
} else {
  action = 'help';
  payload = { chatId };
}

return [{ json: { action, ...payload } }];

const fileId = $json.fileId;
const step = $json.step;
const session = $json.session || { step: 1, answers: {} };
const transcription = $('Transcribe Audio').first().json.text || '';

const fieldMap = {
  1: 'tomorrow_priority', 2: 'todays_hardship',
  3: 'gratitude', 4: 'day_summary', 5: 'todays_idea'
};
const answers = { ...(session.answers || {}), [fieldMap[step]]: transcription };
const nextStep = step + 1;

const questions = {
  2: '2️⃣ 오늘 힘들었거나 아쉬웠던 점은 무엇인가요?',
  3: '3️⃣ 오늘 감사했던 일은 무엇인가요?',
  4: '4️⃣ 오늘 하루를 한 마디로 표현하면?',
  5: '5️⃣ 오늘 떠오른 아이디어나 생각이 있었나요?',
};
const metricsMsg = '마지막이에요! 오늘의 수치를 입력해주세요 📊\n\n기분/에너지(1~10) / 수면시간 / 운동(O or X) / 목표달성률(0~100)\n\n예시: 7 / 6.5 / O / 80';

return [{
  json: {
    chatId: $json.chatId,
    nextStep,
    answers,
    nextMessage: nextStep <= 5 ? questions[nextStep] : metricsMsg,
    isDone: nextStep > 5
  }
}];

const text = $json.metricsText || '';
const session = $json.session || {};
const parts = text.split('/').map(s => s.trim());
const mood_energy = parseInt(parts[0]) || null;
const sleep_hours = parseFloat(parts[1]) || null;
const exercised = (parts[2] || '').toUpperCase() === 'O';
const goal_achievement = parseInt(parts[3]) || null;

if (!mood_energy) {
  return [{ json: { error: true, chatId: $json.chatId,
    msg: '⚠️ 형식이 맞지 않아요.\n예시: 7 / 6.5 / O / 80' } }];
}
return [{ json: {
  chatId: $json.chatId,
  mood_energy, sleep_hours, exercised, goal_achievement,
  answers: session.answers || {}
}}];

const a = $json.answers || {};
const prompt = `당신은 따뜻하고 성찰적인 일기 작가입니다.
아래 답변을 바탕으로 자연스러운 일기 초안을 한국어로 작성해주세요. 200~300자, 1인칭 서술.

- 내일의 우선순위: ${a.tomorrow_priority || '-'}
- 오늘의 어려움: ${a.todays_hardship || '-'}
- 감사한 일: ${a.gratitude || '-'}
- 오늘 하루 한 마디: ${a.day_summary || '-'}
- 오늘의 아이디어: ${a.todays_idea || '-'}`;

return [{ json: { prompt, ...($json) } }];

