const goals = $('Get Goals').first().json;
const arr = Array.isArray(goals) ? goals : [goals];
if (!arr.length || !arr[0].id) {
  return [{ json: { chatId: $json.chatId, msg: '아직 설정된 목표가 없어요.

/goals set year - 연간 목표 설정
/goals set month - 월간 목표 설정
/goals set day - 오늘 목표 설정' } }];
}
const byLevel = { year: [], month: [], day: [] };
for (const g of arr) {
  if (byLevel[g.level]) byLevel[g.level].push(g);
}
let msg = '🎯 나의 목표

';
if (byLevel.year.length)  msg += '📅 연간:
' + byLevel.year.map(g => `• ${g.title} [${g.status}]`).join('
') + '

';
if (byLevel.month.length) msg += '🗓 월간:
' + byLevel.month.map(g => `• ${g.title} [${g.status}]`).join('
') + '

';
if (byLevel.day.length)   msg += '📌 오늘:
' + byLevel.day.map(g => `• ${g.title} [${g.status}]`).join('
');
return [{ json: { chatId: $json.chatId, msg } }];
